# Create a CloudFront distribution with S3 origin
# The distribution automatically uses all 600+ Edge Locations
DIST_ID=$(aws cloudfront create-distribution \
  --distribution-config '{
    "CallerReference": "my-dist-001",
    "Origins": {
      "Quantity": 1,
      "Items": [{
        "Id": "S3-my-bucket",
        "DomainName": "my-bucket.s3.amazonaws.com",
        "S3OriginConfig": {"OriginAccessIdentity": ""}
      }]
    },
    "DefaultCacheBehavior": {
      "TargetOriginId": "S3-my-bucket",
      "ViewerProtocolPolicy": "redirect-to-https",
      "CachePolicyId": "658327ea-f89d-4fab-a63d-7e88639e58f6",
      "Compress": true,
      "AllowedMethods": {"Quantity": 2, "Items": ["GET", "HEAD"]},
      "CachedMethods": {"Quantity": 2, "Items": ["GET", "HEAD"]}
    },
    "Enabled": true,
    "PriceClass": "PriceClass_All",
    "Comment": "Example distribution"
  }' --query 'Distribution.Id' --output text)

echo "Distribution: $DIST_ID"

# Retrieve the distribution domain name (points to nearest PoP automatically)
aws cloudfront get-distribution \
  --id "$DIST_ID" \
  --query 'Distribution.DomainName' --output text

# Create a Route 53 latency-based routing record set
# Route 53 uses Edge Location proximity to determine which region is fastest
aws route53 change-resource-record-sets \
  --hosted-zone-id Z123456789ABC \
  --change-batch '{
    "Changes": [
      {
        "Action": "UPSERT",
        "ResourceRecordSet": {
          "Name": "api.example.com",
          "Type": "A",
          "SetIdentifier": "us-east-1-endpoint",
          "Region": "us-east-1",
          "TTL": 60,
          "ResourceRecords": [{"Value": "203.0.113.10"}],
          "HealthCheckId": "abc12345-1234-1234-1234-abc123456789"
        }
      },
      {
        "Action": "UPSERT",
        "ResourceRecordSet": {
          "Name": "api.example.com",
          "Type": "A",
          "SetIdentifier": "ap-southeast-1-endpoint",
          "Region": "ap-southeast-1",
          "TTL": 60,
          "ResourceRecords": [{"Value": "203.0.113.20"}],
          "HealthCheckId": "def56789-5678-5678-5678-def567890123"
        }
      }
    ]
  }'

// CloudFront Function: redirect /old-path/* to /new-path/* at the edge
// Deployed to ALL PoPs — no cold starts, executes in < 1 ms
function handler(event) {
    var request = event.request;
    var uri = request.uri;

    // Redirect old paths to new paths
    if (uri.startsWith('/old-path/')) {
        return {
            statusCode: 301,
            statusDescription: 'Moved Permanently',
            headers: {
                location: { value: uri.replace('/old-path/', '/new-path/') }
            }
        };
    }

    // Add security headers to all responses passing through this PoP
    request.headers['x-forwarded-for'] = { value: event.viewer.ip };
    return request;
}
